export function getEngines(make: string, model: string, year: number): string[] {
  const entries = ENGINE_DATA[make]?.[model];
  if (!entries) return [];
  const match = entries.find(e => e[0] === year);
  return match ? (match.slice(1) as string[]) : [];
}